"use client";

import Link from "next/link";
import { usePathname } from "next/navigation";

const links = [
  { href: "/feed", label: "Feed" },
  { href: "/leaderboard", label: "Leaderboard" },
  { href: "/give-kudos", label: "Give Kudos", primary: true },
] as const;

export function TopNav() {
  const pathname = usePathname();

  return (
    <nav aria-label="Main navigation" className="flex items-center gap-6">
      {links.map((link) => {
        const isActive = pathname === link.href || (link.href !== "/feed" && pathname.startsWith(link.href));
        return "primary" in link && link.primary ? (
          <Link
            key={link.href}
            href={link.href}
            className={`rounded px-4 py-2 text-sm font-medium transition-colors focus:outline-none focus:ring-2 focus:ring-gray-500 focus:ring-offset-2 ${
              isActive
                ? "bg-gray-800 text-white"
                : "bg-gray-800 text-white hover:bg-gray-700"
            }`}
          >
            {link.label}
          </Link>
        ) : (
          <Link
            key={link.href}
            href={link.href}
            className={`text-sm font-medium transition-colors focus:outline-none focus:ring-2 focus:ring-gray-500 focus:ring-offset-2 rounded ${
              isActive ? "text-gray-900 underline" : "text-gray-600 hover:text-gray-900"
            }`}
          >
            {link.label}
          </Link>
        );
      })}
    </nav>
  );
}
