"use client";

import Link from "next/link";
import { usePathname } from "next/navigation";

const links = [
  { href: "/feed", label: "Feed" },
  { href: "/give-kudos", label: "Give Kudos", primary: true },
  { href: "/leaderboard", label: "Leaderboard" },
] as const;

export function BottomNav() {
  const pathname = usePathname();

  return (
    <nav
      aria-label="Mobile navigation"
      className="fixed bottom-0 left-0 right-0 z-10 flex items-center justify-around border-t border-gray-200 bg-gray-50 px-2 py-2 safe-area-pb lg:hidden"
    >
      {links.map((link) => {
        const isActive = pathname === link.href || (link.href !== "/feed" && pathname.startsWith(link.href));
        return (
          <Link
            key={link.href}
            href={link.href}
            className={`flex flex-1 flex-col items-center gap-1 rounded px-3 py-2 text-xs font-medium transition-colors focus:outline-none focus:ring-2 focus:ring-gray-500 focus:ring-offset-2 ${
              "primary" in link && link.primary
                ? isActive
                  ? "bg-gray-800 text-white"
                  : "bg-gray-800 text-white hover:bg-gray-700"
                : isActive
                  ? "text-gray-900"
                  : "text-gray-600 hover:text-gray-900"
            }`}
          >
            {link.label}
          </Link>
        );
      })}
    </nav>
  );
}
